using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string ModelId = "gpt-4o-mini-2024-07-18";

// --- Tools ---
var notebook = new Notebook();
var webSearchTool = AIFunctionFactory.Create(SearchWebAsync);
var addNoteTool = AIFunctionFactory.Create(notebook.AddNote);
var getNotesTool = AIFunctionFactory.Create(notebook.GetNotes);

// --- Chat client (MEAI abstraction over OpenAI) ---
IChatClient chatClient = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(ModelId).AsIChatClient())
    .Build();

// --- Agent (Microsoft Agent Framework) ---
var researchAgent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to research a topic thoroughly by:
        1. Searching the web for relevant information using the search_web tool.
        2. Taking notes on key findings using the add_note tool.
        3. Searching multiple times with different queries to get comprehensive coverage.
        4. After gathering enough information, retrieving your notes with get_notes and
           providing a well-structured summary to the user.

        Always take notes as you go so you don't lose important details.
        Cite sources where possible.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools: [webSearchTool, addNoteTool, getNotesTool]);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in researchAgent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n✅ Research complete.");

// --- Helper methods ---

static string PromptForTopic()
{
    Console.Write("Enter a topic to research: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrWhiteSpace(input)
        ? "recent advances in quantum computing 2025"
        : input;
}

[Description("Searches the web for information on a given query and returns relevant results.")]
static async Task<string> SearchWebAsync(
    [Description("The search query to look up on the web")] string query,
    CancellationToken cancellationToken = default)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");

    using var httpClient = new HttpClient();
    httpClient.DefaultRequestHeaders.UserAgent.ParseAdd(
        "ResearchAgent/1.0 (compatible; research bot)");

    try
    {
        // Use DuckDuckGo Instant Answer API (no key required)
        var encodedQuery = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

        var response = await httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);

        var results = new List<string>();

        // Extract abstract
        var abstractText = response.GetProperty("Abstract").GetString();
        var abstractSource = response.GetProperty("AbstractSource").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            results.Add($"[{abstractSource}] {abstractText}");
        }

        // Extract related topics
        if (response.TryGetProperty("RelatedTopics", out var relatedTopics))
        {
            foreach (var topic in relatedTopics.EnumerateArray().Take(5))
            {
                if (topic.TryGetProperty("Text", out var text))
                {
                    var topicText = text.GetString();
                    if (!string.IsNullOrWhiteSpace(topicText))
                    {
                        var firstUrl = topic.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : "";
                        results.Add($"- {topicText} (Source: {firstUrl})");
                    }
                }
            }
        }

        // Extract answer if available
        var answer = response.GetProperty("Answer").GetString();
        if (!string.IsNullOrWhiteSpace(answer))
        {
            results.Add($"Direct answer: {answer}");
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : $"No detailed results found for '{query}'. Try refining the search terms.";
    }
    catch (Exception ex)
    {
        return $"Search failed for '{query}': {ex.Message}. Try a different query.";
    }
}

// --- Notebook tool class ---

sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note. Use this to record key findings, facts, or insights discovered during research.")]
    public string AddNote(
        [Description("The note content to save")] string content,
        [Description("Optional source URL or reference for this note")] string? source = null)
    {
        var entry = source is not null
            ? $"{content} [Source: {source}]"
            : content;

        _notes.Add(entry);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved successfully. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all research notes taken so far. Use this before writing your final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes taken yet.";
        }

        var numbered = _notes.Select((n, i) => $"{i + 1}. {n}");
        return $"Research notes ({_notes.Count} total):\n" + string.Join("\n", numbered);
    }
}

